typedef struct _INTERNET_CACHE_GROUP_INFOA {
DWORD dwGroupSize;   DWORD dwGroupFlags;   DWORD dwGroupType;   DWORD dwDiskUsage;   DWORD dwDiskQuota;
DWORD dwOwnerStorage[GROUP_OWNER_STORAGE_SIZE];   CHAR  szGroupName[GROUPNAME_MAX_LENGTH];
} INTERNET_CACHE_GROUP_INFOA, *LPINTERNET_CACHE_GROUP_INFOA;
成员 dwGroupSize
结构的大小，TCHAR。 dwGroupFlags
组标志。 目前，定义的唯一值是CACHEGROUP_FLAG_NONPURGEABLE，指示缓存管理
器不会删除此组中的缓存条目。 dwGroupType
组类型。 目前，定义的唯一值是CACHEGROUP_TYPE_INVALID。 dwDiskUsage
此缓存组的当前磁盘使用情况（以 KB 为单位）。 dwDiskQuota
此缓存组的磁盘配额（以 KB 为单位）。
dwOwnerStorage[GROUP_OWNER_STORAGE_SIZE]
客户端应用程序可用于存储与组相关的信息的数组。 szGroupName[GROUPNAME_MAX_LENGTH]
组名称。

