typedef struct _INTERNET_BUFFERSA {
DWORD                     dwStructSize;   struct _INTERNET_BUFFERSA *Next;
LPCSTR                    lpcszHeader;
DWORD                     dwHeadersLength;   DWORD                     dwHeadersTotal;   LPVOID                    lpvBuffer;
DWORD                     dwBufferLength;   DWORD                     dwBufferTotal;
DWORD                     dwOffsetLow;   DWORD                     dwOffsetHigh;} INTERNET_BUFFERSA, *LPINTERNET_BUFFERSA;
成员 dwStructSize
结构的大小（以字节为单位）。 Next
指向下一个 INTERNET_BUFFERS 结构的指针。 lpcszHeader
指向包含标头的字符串值的指针。 此成员可以 NULL。 dwHeadersLength
如果 lpcszHeader 不 NULL，则 TCHAR中标头的大小。 dwHeadersTotal
标头的大小（如果缓冲区中没有足够的内存）。 lpvBuffer
指向数据缓冲区的指针。 dwBufferLength
如果 lpvBuffer 不 NULL，则缓冲区的大小（以字节为单位）。 dwBufferTotal
资源的总大小（以字节为单位）。 dwOffsetLow
保留;请勿使用。 dwOffsetHigh 保留;请勿使用。

